import { describe, expect, it } from 'vitest';
import {
  AEON_STREAM_PNEUMA_INTERNAL,
  THOTH_GATE_TELEMETRY_FRAME_KIND,
  canonicalThothGateTelemetryMetrics,
  encodeThothGateTelemetryFrame,
  isThothGateTelemetryFrame,
  thothGateTelemetryReadyHandoffCount,
  thothGateTelemetryTotalPressure,
} from '../src/thoth-gate-telemetry';

describe('Thoth gate telemetry', () => {
  it('builds the canonical multi-gate taxonomy on stream 2002', () => {
    const metrics = canonicalThothGateTelemetryMetrics();
    expect(metrics.scores.map((score) => score.gate)).toEqual([
      'horoscope',
      'oath',
      'prana',
      'ki',
      'chi',
      'tai-chi',
      'mudra',
      'cognitive',
      'aura',
      'safety',
      'audio-shield',
    ]);
    expect(metrics.nonAuthoritative).toBe(true);
    expect(metrics.sourceBacked).toBe(true);
    expect(metrics.gateBoundariesPreserved).toBe(true);
    expect(
      metrics.scores.find((score) => score.gate === 'oath')?.perspective,
    ).toBe('stability-binding');
    expect(
      metrics.scores.find((score) => score.gate === 'prana')?.perspective,
    ).toBe('body-gate-damping');
    expect(
      metrics.scores.find((score) => score.gate === 'ki')?.perspective,
    ).toBe('preincident-defense');
    expect(
      metrics.scores.find((score) => score.gate === 'tai-chi')?.perspective,
    ).toBe('moving-polarity-balance');

    const frame = encodeThothGateTelemetryFrame('thoth-host', metrics);
    expect(isThothGateTelemetryFrame(frame)).toBe(true);
    expect(frame.mediaType.Abstract).toBe(THOTH_GATE_TELEMETRY_FRAME_KIND);
    expect(frame.attributes.aeon_stream_id).toBe(
      String(AEON_STREAM_PNEUMA_INTERNAL),
    );
    expect(frame.attributes.gate_score_count).toBe('11');
    expect(frame.attributes.gate_names).toBe(
      'horoscope|oath|prana|ki|chi|tai-chi|mudra|cognitive|aura|safety|audio-shield',
    );
    expect(frame.attributes.non_authoritative).toBe('true');
    expect(frame.attributes.no_source_authority_claim).toBe('true');
    expect(frame.barcode.beta1).toBe(11);
    expect(frame.deficit).toBe(thothGateTelemetryTotalPressure(metrics));
    expect(frame.attributes.gate_ready_handoff_count).toBe(
      String(thothGateTelemetryReadyHandoffCount(metrics)),
    );
  });
});
